+// transactionalReloadState keeps the last successful configuration and the single
+// observable outcome of the most recent reload attempt.
+type transactionalReloadState struct {
+	mu       sync.RWMutex
+	path     string
+	logger   *slog.Logger
+	lastGood *config.Config
+	result   web.ReloadStatus
+}
+
+func newTransactionalReloadState(path string, logger *slog.Logger) *transactionalReloadState {
+	s := &transactionalReloadState{path: path, logger: logger, result: web.ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}}
+	b, err := os.ReadFile(path)
+	if err == nil && json.Unmarshal(b, &s.result) == nil {
+		if s.result.AppliedReloaders == nil { s.result.AppliedReloaders = []string{} }
+		if s.result.ReloaderTimingsMS == nil { s.result.ReloaderTimingsMS = map[string]int64{} }
+	}
+	return s
+}
+
+func (s *transactionalReloadState) status() web.ReloadStatus {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	r := s.result
+	r.AppliedReloaders = append([]string(nil), r.AppliedReloaders...)
+	r.ReloaderTimingsMS = maps.Clone(r.ReloaderTimingsMS)
+	return r
+}
+
+func (s *transactionalReloadState) persist() {
+	b, err := json.Marshal(s.result)
+	if err != nil { return }
+	if err := os.MkdirAll(filepath.Dir(s.path), 0o755); err == nil {
+		if err := os.WriteFile(s.path, b, 0o644); err != nil { s.logger.Warn("Failed to persist reload status", "err", err) }
+	}
+}
+
+func (s *transactionalReloadState) reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStep *safePromQLNoStepSubqueryInterval, callback func(bool), record bool, rls ...reloader) error {
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		if record { s.record(web.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339), ErrorCategory: "load_error", ErrorMessage: err.Error(), AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}) }
+		callback(false)
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil { conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig }
+	r := web.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339), LastReloadSuccessful: true, ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+	for _, rl := range rls {
+		started := time.Now()
+		err := rl.reloader(conf)
+		r.ReloaderTimingsMS[rl.name] = time.Since(started).Milliseconds()
+		if err != nil {
+			r.LastReloadSuccessful, r.ErrorCategory, r.ErrorMessage, r.FailedReloader = false, "apply_error", err.Error(), rl.name
+			if len(r.AppliedReloaders) > 0 && s.lastGood != nil {
+				r.RollbackAttempted, r.RollbackSuccessful = true, true
+				for _, rollback := range rls { if e := rollback.reloader(s.lastGood); e != nil { r.RollbackSuccessful = false; r.ErrorCategory = "rollback_error"; r.ErrorMessage = e.Error(); r.FailedReloader = rollback.name; break } }
+			}
+			if record { s.record(r) }; callback(false); return fmt.Errorf("failed to apply configuration with reloader %s: %w", rl.name, err)
+		}
+		r.AppliedReloaders = append(r.AppliedReloaders, rl.name)
+	}
+	s.lastGood = conf
+	updateGoGC(conf, logger); noStep.Set(conf.GlobalConfig.EvaluationInterval)
+	if record { s.record(r) }; callback(true)
+	return nil
+}
+
+func (s *transactionalReloadState) record(r web.ReloadStatus) { s.mu.Lock(); s.result = r; s.persist(); s.mu.Unlock() }
